load("@rules_systemrdl//systemrdl:system_rdl_toolchain.bzl", "system_rdl_toolchain") system_rdl_toolchain(name, exporter_args, exporter_dirs, exporter_files, peakrdl, peakrdl_config) A SystemRDL toolchain. Plugins: Additional exporters are supported via a combination of the peakrdl and peakrdl_config attributes. load("@rules_venv//python:py_library.bzl", "py_library")
load("@rules_systemrdl//systemrdl:system_rdl_toolchain.bzl", "system_rdl_toolchain") py_library( name = "peakrdl_toml", srcs = ["peakrdl_toml.py"], deps = [ "@pip_deps//peakrdl", "@pip_deps//tomli", ],
) PLUGINS = [ ":peakrdl_toml"
] py_library( name = "peakrdl", deps = [ "@pip_deps//peakrdl", ] + PLUGINS,
) system_rdl_toolchain( name = "system_rdl_toolchain", peakrdl = ":peakrdl", peakrdl_config = "peakrdl.toml", exporter_files = { "regblock": [ "sv={name}.sv", "pkg={name}_pkg.sv", ], "toml": [ "toml={name}.toml", ], }, exporter_dirs = { "html": [ "dir={name}_html", ], },
) toolchain( name = "toolchain", toolchain = ":system_rdl_toolchain", toolchain_type = "@rules_systemrdl//systemrdl:toolchain_type", visibility = ["//visibility:public"],
) peakrdl.toml: # https://peakrdl.readthedocs.io/en/latest/configuring.html
[peakrdl]
# The import path should be the repo realtive import path of the plugin.
plugins.exporters.toml = "tools.system_rdl.peakrdl_toml:TomlExporter" Now with the toolchain configured. all system_rdl_library targets built in the same configuration as the registered toolchain will have an additional output group system_rdl_toml that is the output of the custom exporter.

